#include <bits/stdc++.h>
using namespace std;

vector<int> processQueries(int Q, vector<pair<int, int>>& queries) {
    vector<int> arr;  // initially empty array
    int xorValue = 0; // to track cumulative XOR value

    for(auto query : queries) {
        int type = query.first;
        int val = query.second;

        if(type == 1) {
            // Type 1: Insert value at end
            // XOR with cumulative value before inserting
            arr.push_back(val ^ xorValue);
        } else {
            // Type 2: XOR all elements with val
            // Just update cumulative XOR
            xorValue ^= val;
        }
    }

    // Apply final cumulative XOR to all elements
    if(xorValue != 0) {
        for(int& x : arr) {
            x ^= xorValue;
        }
    }

    return arr;
}

int main() {
    int Q;
    cin >> Q;

    vector<pair<int, int>> queries(Q);
    for(int i = 0; i < Q; i++) {
        cin >> queries[i].first >> queries[i].second;
    }

    vector<int> result = processQueries(Q, queries);

    for(int x : result) {
        cout << x << " ";
    }
    cout << endl;

    return 0;
}
